SELECT name
FROM design_elements
WHERE status = 'published';

SELECT name
FROM design_elements
WHERE status = 'published';

SELECT name, lastUpdatedAt
FROM design_elements
ORDER BY lastUpdatedAt DESC;

SELECT DISTINCT modelId
FROM design_elements
ORDER BY modelId ASC;

SELECT name
FROM design_projects
ORDER BY lastUpdatedAt DESC;

external_knowledge:
; Published means the design element is live and accessible to the public; 
; A specific design project refers to a unique project with a distinct project ID (replaced by 1 in the query);
; Unresolved comments refer to comments that have not been resolved yet (c.resolved = 0).
